import React, { useState } from "react";
import axios from "axios";
import toast from 'react-hot-toast';

// Helper function to trim and clean values safely
const cleanString = (str) => (typeof str === 'string' ? str.trim().replace(/\s+/g, ' ') : str);

function AddStall() {
  const [formData, setFormData] = useState({
    stallName: "",
    stallNumber: "",
    stallType: "",
    eventName: "",
    locationZone: "",
    size: "",
    price: "",
    status: "Available",
    description: "",
  });

  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  // --- VALIDATION RULES ---
  const validateField = (name, value) => {
    let error = null;

    switch (name) {
      case "stallName":
        const cleanName = cleanString(value);
        if (!cleanName) error = "Stall name is required.";
        else if (!/^[a-zA-Z\s]+$/.test(cleanName)) error = "Stall name must contain only letters and spaces.";
        else if (cleanName.length < 5 || cleanName.length > 35) error = "Stall name must be between 5 and 35 characters.";
        break;

      case "stallNumber":
        if (!value) error = "Stall number is required.";
        else if (!/^[A-Z0-9]+$/.test(value)) error = "Use only capital letters and numbers.";
        else if (value.length < 2 || value.length > 5) error = "Stall number must be 2 to 5 characters long.";
        break;

      case "stallType":
        if (!value) error = "Please select a stall type.";
        break;

      case "eventName":
        const cleanEvent = cleanString(value);
        if (!cleanEvent) error = "Event name is required.";
        else if (!/^[A-Za-z0-9\s]+$/.test(cleanEvent)) error = "Event name can contain only letters, numbers, and spaces.";
        else if (cleanEvent.length < 5 || cleanEvent.length > 20) error = "Event name must be between 5 and 20 characters.";
        break;

      case "locationZone":
        if (!value) error = "Please select a location zone.";
        break;

      case "size":
        if (!value) error = "Please select a stall size.";
        break;

      case "price":
        if (value === "" || value === null) error = "Price is required.";
        else if (isNaN(value)) error = "Price must contain numbers only.";
        else if (Number(value) < 0) error = "Price cannot be negative.";
        break;

      case "status":
        if (!value) error = "Please select a valid status.";
        break;

      case "description":
        const cleanDesc = cleanString(value);
        if (cleanDesc) {
          if (cleanDesc.length < 10 || cleanDesc.length > 200) error = "Description must be between 10 and 200 characters.";
          else if (!/^[A-Za-z0-9\s,.\-]+$/.test(cleanDesc)) error = "Use letters, numbers, spaces, commas, and simple punctuation only.";
        }
        break;

      default:
        break;
    }
    return error;
  };

  const handleBlur = (e) => {
    const { name, value } = e.target;
    setTouched((prev) => ({ ...prev, [name]: true }));

    // Auto-trim on blur for text fields
    let newValue = value;
    if (['stallName', 'eventName', 'description'].includes(name)) {
      newValue = cleanString(value);
      setFormData(prev => ({ ...prev, [name]: newValue }));
    }

    const error = validateField(name, newValue);
    setErrors((prev) => ({ ...prev, [name]: error }));
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Auto-uppercase for Stall Number
    let processedValue = value;
    if (name === "stallNumber") {
      processedValue = value.toUpperCase();
    }

    setFormData((prev) => ({ ...prev, [name]: processedValue }));

    // If field was already touched and had an error, validate on change for better UX
    if (touched[name]) {
      const error = validateField(name, processedValue);
      setErrors((prev) => ({ ...prev, [name]: error }));
    }
  };

  // Prevent invalid characters in price field (e', '-', '+', '.')
  const handlePriceKeyDown = (e) => {
    if (['e', 'E', '-', '+'].includes(e.key)) {
      e.preventDefault();
    }
  };

  const validateAll = () => {
    const newErrors = {};
    Object.keys(formData).forEach((key) => {
      const err = validateField(key, formData[key]);
      if (err) newErrors[key] = err;
    });
    setErrors(newErrors);

    // Mark all as touched
    const allTouched = Object.keys(formData).reduce((acc, key) => {
      acc[key] = true;
      return acc;
    }, {});
    setTouched(allTouched);

    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateAll()) return;

    setIsSubmitting(true);
    try {
      // Mock unique ID check behavior (simulating a backend rejection if needed, though we will proceed to post)
      const submitData = {
        ...formData,
        stallName: cleanString(formData.stallName),
        eventName: cleanString(formData.eventName),
        description: cleanString(formData.description),
        price: Number(formData.price)
      };

      const res = await axios.post("http://localhost:5000/api/stalls", submitData);

      toast.success("Stall Added Successfully!");

      // reset form
      setFormData({
        stallName: "",
        stallNumber: "",
        stallType: "",
        eventName: "",
        locationZone: "",
        size: "",
        price: "",
        status: "Available",
        description: "",
      });
      setTouched({});
      setErrors({});
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.message || "Error adding stall");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Helper to get input CSS class based on validation state
  const getInputClass = (name) => {
    if (!touched[name]) return "form-control";
    return errors[name] ? "form-control invalid-border" : "form-control valid-border";
  };

  return (
    <div className="mx-auto" style={{ maxWidth: '900px' }}>

      {/* Inline styles for custom validation borders */}
      <style>
        {`
          .invalid-border { border-color: var(--red) !important; outline-color: var(--red); }
          .valid-border { border-color: var(--green) !important; }
          .error-text { color: var(--red); font-size: 0.75rem; margin-top: 0.25rem; font-weight: 500; display: block; }
          .helper-text { color: var(--gray-400); font-size: 0.75rem; display: block; margin-top: 0.125rem; }
        `}
      </style>

      <div className="page-header mb-6">
        <div>
          <h1 className="page-title">Add New Stall</h1>
          <p className="page-subtitle">Create a stall for vendors to book</p>
        </div>
      </div>

      <div className="card">
        <form onSubmit={handleSubmit}>
          <div className="grid grid-cols-2 gap-6">

            {/* Row 1 */}
            <div className="form-group">
              <label className="form-label">Stall Name *</label>
              <input
                type="text"
                name="stallName"
                placeholder="e.g. Premium Food Spot"
                value={formData.stallName}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("stallName")}
                maxLength="35"
              />
              {errors.stallName && touched.stallName && <span className="error-text">{errors.stallName}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Stall Number (Map ID) *</label>
              <input
                type="text"
                name="stallNumber"
                placeholder="e.g. A1, B2"
                value={formData.stallNumber}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("stallNumber")}
                maxLength="5"
              />
              <span className="helper-text">Must be unique per event. Caps and numbers only.</span>
              {errors.stallNumber && touched.stallNumber && <span className="error-text">{errors.stallNumber}</span>}
            </div>

            {/* Row 2 */}
            <div className="form-group">
              <label className="form-label">Stall Type *</label>
              <select
                name="stallType"
                value={formData.stallType}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("stallType")}
              >
                <option value="" disabled>Select a type...</option>
                <option value="Food Stall">Food Stall</option>
                <option value="Game Stall">Game Stall</option>
                <option value="Retail">Retail</option>
                <option value="Sponsor Booth">Sponsor Booth</option>
              </select>
              {errors.stallType && touched.stallType && <span className="error-text">{errors.stallType}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Event Name *</label>
              <input
                type="text"
                name="eventName"
                placeholder="e.g. Career Fair 2026"
                value={formData.eventName}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("eventName")}
                maxLength="20"
              />
              {errors.eventName && touched.eventName && <span className="error-text">{errors.eventName}</span>}
            </div>

            {/* Row 3 */}
            <div className="form-group">
              <label className="form-label">Location Zone *</label>
              <select
                name="locationZone"
                value={formData.locationZone}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("locationZone")}
              >
                <option value="" disabled>Select a zone...</option>
                <option value="Zone A">Zone A</option>
                <option value="Zone B">Zone B</option>
                <option value="Zone C">Zone C</option>
                <option value="VIP Area">VIP Area</option>
                <option value="Campus Green">Campus Green</option>
              </select>
              {errors.locationZone && touched.locationZone && <span className="error-text">{errors.locationZone}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Size *</label>
              <select
                name="size"
                value={formData.size}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("size")}
              >
                <option value="" disabled>Select a size...</option>
                <option value="Small (2x2m)">Small (2x2m)</option>
                <option value="Medium (3x3m)">Medium (3x3m)</option>
                <option value="Large (5x5m)">Large (5x5m)</option>
              </select>
              {errors.size && touched.size && <span className="error-text">{errors.size}</span>}
            </div>

            {/* Row 4 */}
            <div className="form-group">
              <label className="form-label">Price (LKR) *</label>
              <input
                type="number"
                name="price"
                placeholder="0"
                value={formData.price}
                onChange={handleChange}
                onBlur={handleBlur}
                onKeyDown={handlePriceKeyDown}
                className={getInputClass("price")}
                min="0"
                step="1"
                inputMode="numeric"
              />
              {errors.price && touched.price && <span className="error-text">{errors.price}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Status *</label>
              <select
                name="status"
                value={formData.status}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("status")}
              >
                <option value="Available">Available</option>
                <option value="Reserved">Pending Request</option>
                <option value="Booked">Booked</option>
              </select>
              {errors.status && touched.status && <span className="error-text">{errors.status}</span>}
            </div>

            {/* Row 5 - Full Width */}
            <div className="form-group col-span-full">
              <label className="form-label">Description / Amenities</label>
              <textarea
                name="description"
                placeholder="e.g. Includes 2 chairs, 1 table, 15A power socket"
                value={formData.description}
                onChange={handleChange}
                onBlur={handleBlur}
                className={getInputClass("description")}
                rows="3"
                maxLength="200"
                style={{ resize: 'vertical' }}
              />
              {errors.description && touched.description && <span className="error-text">{errors.description}</span>}
            </div>

          </div>

          <div className="flex gap-4 mt-6" style={{ justifyContent: 'flex-end', paddingTop: '1.5rem', borderTop: '1px solid var(--gray-100)' }}>
            <button
              type="button"
              className="btn btn-outline"
              onClick={() => {
                setFormData({
                  stallName: "", stallNumber: "", stallType: "", eventName: "",
                  locationZone: "", size: "", price: "", status: "Available", description: ""
                });
                setTouched({});
                setErrors({});
              }}
            >
              Cancel
            </button>
            <button
              type="submit"
              className="btn btn-primary"
              disabled={isSubmitting || Object.keys(errors).length > 0}
            >
              {isSubmitting ? "Saving..." : "Save Stall"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddStall;

import React, { useEffect, useState } from "react";
import axios from "axios";
import toast from 'react-hot-toast';

function ViewStalls() {
  const [stalls, setStalls] = useState([]);

  // Fetch data from backend
  const fetchStalls = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/stalls");
      setStalls(res.data.data);
    } catch (error) {
      console.error(error);
    }
  };

  // Run when page loads
  useEffect(() => {
    fetchStalls();
  }, []);

  // Delete stall
  const deleteStall = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/stalls/${id}`);
      toast.success("Deleted Successfully");
      fetchStalls(); // refresh list
    } catch (error) {
      console.error(error);
      toast.error("Error deleting");
    }
  };

  return (
    <div>
      <h2>All Stalls</h2>

      {stalls.length === 0 ? (
        <p>No stalls available</p>
      ) : (
        stalls.map((stall) => (
          <div
            key={stall._id}
            style={{
              border: "1px solid black",
              padding: "10px",
              marginBottom: "10px",
            }}
          >
            <h3>{stall.stallName}</h3>
            <p><strong>Type:</strong> {stall.stallType}</p>
            <p><strong>Event:</strong> {stall.eventName}</p>
            <p><strong>Size:</strong> {stall.size}</p>
            <p><strong>Price:</strong> Rs. {stall.price}</p>
            <p><strong>Zone:</strong> {stall.locationZone}</p>
            <p><strong>Status:</strong> {stall.status}</p>

            <button onClick={() => deleteStall(stall._id)}>
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default ViewStalls;

