import React, { createContext, useContext, useState, useEffect } from 'react';
import axios from 'axios';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedToken = localStorage.getItem('eventaura_token');
    const savedUser = localStorage.getItem('eventaura_user');
    if (savedToken && savedUser) {
      setToken(savedToken);
      setUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const login = async (username, password) => {
    const res = await axios.post('http://localhost:5000/api/auth/login', { username, password });
    if (res.data.success) {
      setToken(res.data.token);
      setUser(res.data.user);
      localStorage.setItem('eventaura_token', res.data.token);
      localStorage.setItem('eventaura_user', JSON.stringify(res.data.user));
      return res.data.user;
    }
    throw new Error(res.data.message);
  };

  const register = async (data) => {
    const res = await axios.post('http://localhost:5000/api/auth/register', data);
    if (res.data.success) {
      setToken(res.data.token);
      setUser(res.data.user);
      localStorage.setItem('eventaura_token', res.data.token);
      localStorage.setItem('eventaura_user', JSON.stringify(res.data.user));
      return res.data.user;
    }
    throw new Error(res.data.message);
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('eventaura_token');
    localStorage.removeItem('eventaura_user');
  };

  return (
    <AuthContext.Provider value={{ user, token, loading, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
};

export default AuthContext;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useParams, Link } from 'react-router-dom';
import { QRCodeSVG } from 'qrcode.react';
import toast from 'react-hot-toast';

const StallDetails = () => {
  const { id } = useParams();
  const [stall, setStall] = useState(null);

  useEffect(() => {
    const fetchStall = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/stalls/${id}`);
        if (res.data.success) {
          setStall(res.data.data);
        }
      } catch (err) {
        console.error(err);
      }
    };
    fetchStall();
  }, [id]);

  if (!stall) return <div className="p-8">Loading stall details...</div>;

  const currentUrl = typeof window !== 'undefined' ? window.location.href : '';

  return (
    <div style={{ backgroundColor: '#f8fafc', minHeight: '100vh', padding: '3rem 2rem' }}>
      <div className="max-w-[1200px] mx-auto">
        <div className="mb-8">
          <button onClick={() => window.history.back()} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--gray-500)', fontSize: '0.875rem', fontWeight: '600', marginBottom: '1rem', background: 'none', border: 'none', cursor: 'pointer', transition: 'color 0.2s' }} onMouseEnter={(e) => e.target.style.color = 'var(--sliit-navy)'} onMouseLeave={(e) => e.target.style.color = 'var(--gray-500)'}>
            ΓåÉ Back to Map
          </button>
          <div className="page-header" style={{ borderBottom: '1px solid var(--gray-200)', paddingBottom: '1.5rem' }}>
            <div>
              <div className="flex items-center gap-4 mb-2">
                <h1 className="page-title font-black text-sliit-navy" style={{ fontSize: '2.5rem', lineHeight: '1.2' }}>{stall.stallName}</h1>
                {stall.status === 'Available' && <span className="badge badge-success text-[0.9rem]" style={{ padding: '0.35rem 1rem' }}>Available</span>}
                {stall.status === 'Reserved' && <span className="badge badge-warning text-[0.9rem]" style={{ padding: '0.35rem 1rem' }}>Pending</span>}
                {stall.status === 'Booked' && <span className="badge badge-neutral text-[0.9rem]" style={{ padding: '0.35rem 1rem' }}>Booked</span>}
              </div>
              <p className="page-subtitle" style={{ fontSize: '1.1rem', fontWeight: '500' }}>ID: <span className="text-orange-500 font-bold">{stall.stallNumber}</span> ΓÇó {stall.eventName}</p>
            </div>

            {stall.status === 'Available' && (
              <Link to={`/vendor/stalls/request/${stall._id}`} className="btn btn-primary text-base" style={{ padding: '0.75rem 2rem', borderRadius: '12px', boxShadow: '0 4px 14px rgba(0, 47, 108, 0.3)' }}>Book This Stall</Link>
            )}
          </div>
        </div>

      <div className="grid gap-8" style={{ gridTemplateColumns: 'minmax(0, 2fr) minmax(0, 1fr)' }}>

        <div className="flex flex-col gap-8">
          {/* Main Details Card */}
          <div className="card" style={{ padding: '2.5rem', borderRadius: '24px', boxShadow: '0 10px 25px rgba(0, 0, 0, 0.03)', border: '1px solid var(--gray-100)' }}>
            <h3 style={{ fontSize: '1.25rem', color: 'var(--sliit-navy)', fontWeight: '800', marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
              <span className="bg-orange-500" style={{ display: 'block', width: '4px', height: '1.25rem', borderRadius: '4px' }}></span>
              Stall Information
            </h3>

            <div className="grid grid-cols-2" style={{ gap: '2.5rem' }}>
              <div>
                <div className="text-slate-500 text-sm font-semibold uppercase mb-2" style={{ letterSpacing: '0.05em' }}>Type</div>
                <div className="font-bold text-xl text-slate-900">{stall.stallType}</div>
              </div>
              <div>
                <div className="text-slate-500 text-sm font-semibold uppercase mb-2" style={{ letterSpacing: '0.05em' }}>Location Zone</div>
                <div className="font-bold text-xl text-slate-900">{stall.locationZone}</div>
              </div>
              <div>
                <div className="text-slate-500 text-sm font-semibold uppercase mb-2" style={{ letterSpacing: '0.05em' }}>Size Specifications</div>
                <div className="font-bold text-xl text-slate-900">{stall.size}</div>
              </div>
              <div className="text-white flex flex-col justify-center" style={{ background: 'linear-gradient(135deg, var(--sliit-navy-light), var(--sliit-navy))', borderRadius: '16px', padding: '1.5rem' }}>
                <div className="text-sm font-semibold uppercase mb-2" style={{ letterSpacing: '0.05em', color: 'rgba(255, 255, 255, 0.8)' }}>Booking Price</div>
                <div className="font-black text-[1.75rem]">LKR {stall.price}</div>
              </div>
            </div>

            <hr className="border-none" style={{ borderTop: '1px solid var(--gray-100)', margin: '3rem 0 2rem' }} />

            <h4 style={{ fontSize: '1rem', color: 'var(--gray-800)', fontWeight: '700', marginBottom: '1.25rem' }}>Description & Amenities</h4>
            <div style={{ backgroundColor: 'var(--gray-50)', border: '1px solid var(--gray-200)', padding: '1.5rem', borderRadius: '16px', color: 'var(--gray-700)', lineHeight: '1.7', fontSize: '0.95rem' }}>
              {stall.description || "No specific description or amenities provided for this stall."}
            </div>
          </div>
        </div>

        {/* Sidebar Cards */}
        <div className="flex flex-col gap-8">

          {/* QR Code Card */}
          <div className="card flex flex-col items-center text-center" style={{ padding: '2.5rem', borderRadius: '24px', background: 'linear-gradient(180deg, white 0%, #f8fafc 100%)', border: '1px solid var(--gray-100)', boxShadow: '0 10px 25px rgba(0, 0, 0, 0.03)' }}>
            <h3 style={{ fontSize: '1.1rem', color: 'var(--sliit-navy)', fontWeight: '800', marginBottom: '1.5rem' }}>Stall QR Code</h3>

            <div className="mb-6" style={{ padding: '1.25rem', background: 'white', borderRadius: '16px', border: '1px solid var(--gray-200)', boxShadow: '0 4px 15px rgba(0, 0, 0, 0.05)' }}>
