          {/* Status Context Card */}
          <div className="card" style={{ backgroundColor: stall.status === 'Available' ? 'var(--sliit-green-light)' : 'var(--gray-50)', border: stall.status === 'Available' ? '1px solid #bbf7d0' : '1px solid var(--gray-200)', borderRadius: '20px', padding: '1.5rem' }}>
