import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const StallLayoutMap = ({ role = 'admin' }) => {
  const [stalls, setStalls] = useState([]);
  const [selectedStall, setSelectedStall] = useState(null);
  const navigate = useNavigate();

  const formatPrice = (val) => {
    if (!val) return '0';
    return val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, " ");
  };

  useEffect(() => {
    const fetchStalls = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/stalls');
        if (res.data.success) {

          const zones = {};
          res.data.data.forEach(stall => {
            if (!zones[stall.locationZone]) zones[stall.locationZone] = [];
            zones[stall.locationZone].push(stall);
          });

          let stallsWithCoords = [];
          Object.keys(zones).forEach(zone => {
            zones[zone].forEach((stall, index) => {
              let x, y;
              if (zone === 'VIP Area') {
                x = 150 + (index % 8) * 80; y = 140 + Math.floor(index / 8) * 60;
              } else if (zone === 'Zone A') {
                x = 130 + (index % 3) * 70; y = 320 + Math.floor(index / 3) * 60;
              } else if (zone === 'Zone B') {
                x = 510 + (index % 3) * 70; y = 320 + Math.floor(index / 3) * 60;
              } else if (zone === 'Zone C') {
                x = 340 + (index % 2) * 70; y = 320 + Math.floor(index / 2) * 60;
              } else {
                // Campus Green or others
                x = 340 + (index % 2) * 70; y = 200 + Math.floor(index / 2) * 60;
              }
              stallsWithCoords.push({ ...stall, x, y });
            });
          });

          setStalls(stallsWithCoords);
        }
      } catch (err) {
        console.error(err);
      }
    };
    fetchStalls();
  }, []);

  const getStallColor = (status) => {
    switch (status) {
      case 'Available': return 'var(--green-light)';
      case 'Reserved': return 'var(--orange-light)';
      case 'Booked': return 'var(--gray-300)';
      default: return 'var(--white)';
    }
  };

  const getBorderColor = (status) => {
    switch (status) {
      case 'Available': return 'var(--green)';
      case 'Reserved': return 'var(--orange)';
      case 'Booked': return 'var(--black)';
      default: return 'var(--gray-400)';
    }
  };

  const getTextColor = (status) => {
    switch (status) {
      case 'Available': return '#14532D';
      case 'Reserved': return '#78350F';
      case 'Booked': return 'var(--white)';
      default: return 'var(--black)';
    }
