      </div>

      <div className="grid gap-8" style={{ gridTemplateColumns: '1fr 350px' }}>

        {/* SVG Interactive Map Area */}
        <div className="card" style={{ padding: '0', overflow: 'hidden', position: 'relative', height: '600px', backgroundColor: 'var(--gray-50)', border: '2px solid var(--gray-200)' }}>

          <svg width="100%" height="100%" viewBox="0 0 800 600" style={{ position: 'absolute', top: 0, left: 0 }}>
            <defs>
              <linearGradient id="eventGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor="#fef3c7" />
                <stop offset="100%" stopColor="#fde68a" />
              </linearGradient>
            </defs>
            {/* Campus Background Elements (Paths, Grass, Buildings) */}
            <rect x="0" y="0" width="800" height="600" fill="#f0fdf4" /> {/* Base grass */}

            {/* VIP / Main Event Layer */}
            <rect x="100" y="80" width="600" height="150" fill="url(#eventGradient)" rx="16" stroke="#f59e0b" strokeWidth="4" style={{ filter: 'drop-shadow(0 0 15px rgba(245, 158, 11, 0.4))' }} />
            <text x="400" y="110" textAnchor="middle" fill="#78350f" fontSize="20" fontWeight="900" letterSpacing="0.2em">Γ¡É MAIN EVENT STAGE Γ¡É</text>
            <text x="400" y="130" textAnchor="middle" fill="#92400e" fontSize="12" fontWeight="bold">HIGH TRAFFIC ZONE</text>

            {/* Zone A Panel */}
            <rect x="80" y="270" width="220" height="200" fill="#f8fafc" rx="16" stroke="#cbd5e1" strokeWidth="2" />
            <text x="190" y="295" textAnchor="middle" fill="#64748b" fontSize="13" fontWeight="bold" letterSpacing="0.05em">ZONE A (WEST WING)</text>

