              onClick={() => { if(window.confirm('Are you sure you want to cancel? Any unsaved changes will be lost.')) navigate('/admin/stalls/list'); }}
            >
              Cancel
            </button>
            <button 
              type="submit" 
              className="btn btn-primary"
              disabled={isSubmitting || Object.values(errors).some(err => err !== null && err !== undefined && err !== "")}
            >
              {isSubmitting ? "Saving..." : "Save Stall"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

