import React, { useState, useEffect } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';

const BookingRequests = () => {
  const [requests, setRequests] = useState([]);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/stall-bookings');
      if (res.data.success) {
        setRequests(res.data.data);
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleAccept = async (id) => {
    if (!window.confirm("Are you sure you want to accept this request?")) return;
    try {
      await axios.put(`http://localhost:5000/api/stall-bookings/${id}/accept`);
      toast.success('Request accepted! Vendor notified to pay advance.');
      fetchRequests();
    } catch (err) {
      toast.error('Error accepting: ' + (err.response?.data?.message || err.message));
    }
  };

  const handleApprove = async (id) => {
    if (!window.confirm("Are you sure you want to confirm and lock this booking?")) return;
    try {
      await axios.put(`http://localhost:5000/api/stall-bookings/${id}/approve`);
      toast.success('Booking approved successfully!');
      fetchRequests();
    } catch (err) {
      toast.error('Error approving: ' + (err.response?.data?.message || err.message));
    }
  };

  const handleReject = async (id) => {
    if (!window.confirm("Are you sure you want to cancel this request?")) return;
    try {
      await axios.put(`http://localhost:5000/api/stall-bookings/${id}/reject`);
      toast.success('Booking rejected. Stall is now available.');
      fetchRequests();
    } catch (err) {
      toast.error('Error rejecting: ' + (err.response?.data?.message || err.message));
    }
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Booking Approvals</h1>
          <p className="page-subtitle">Review vendor stall requests</p>
        </div>
      </div>

      <div className="card">
        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
          <thead>
            <tr className="text-slate-500" style={{ borderBottom: '1px solid var(--gray-200)' }}>
              <th style={{ padding: '1rem 0' }}>Request Details</th>
              <th style={{ padding: '1rem 0' }}>Stall Info</th>
              <th style={{ padding: '1rem 0' }}>Vendor Intel</th>
              <th style={{ padding: '1rem 0' }}>Status</th>
              <th style={{ padding: '1rem 0', textAlign: 'right' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map(req => (
              <tr key={req._id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                <td style={{ padding: '1rem 0' }}>
                  <div className="font-semibold">{req.vendorName}</div>
                  <div className="text-xs text-slate-500">{new Date(req.createdAt).toLocaleDateString()}</div>
                </td>
                <td style={{ padding: '1rem 0' }}>
                  <div style={{ fontWeight: '500' }}>{req.stallNumber} - {req.stallName}</div>
                  <div className="text-xs text-slate-500">{req.eventName}</div>
                </td>
                <td style={{ padding: '1rem 0' }}>
                  <div className="text-sm">{req.businessName}</div>
                  <div className="text-xs text-slate-500">{req.itemsToSell}</div>
                </td>
                <td style={{ padding: '1rem 0' }}>
                  {req.status === 'Pending' && <span className="badge badge-warning">Needs Approval</span>}
                  {req.status === 'PreApproved' && <span className="badge badge-warning text-white" style={{ backgroundColor: 'var(--orange)' }}>Awaiting Vendor Payment</span>}
                  {req.status === 'Confirmed' && <span className="badge badge-success text-white" style={{ backgroundColor: 'var(--blue)' }}>Payment Received</span>}
                  {req.status === 'Approved' && <span className="badge badge-success">Locked</span>}
                  {req.status === 'Rejected' && <span className="badge badge-danger">Cancelled</span>}
                </td>
                <td style={{ padding: '1rem 0', textAlign: 'right' }}>
                  {(req.status === 'Pending' || req.status === 'Confirmed') && (
                    <div className="flex gap-2" style={{ justifyContent: 'flex-end' }}>
                      {req.status === 'Pending' && (
                        <button onClick={() => handleAccept(req._id)} className="btn btn-outline text-xs text-blue-500" style={{ padding: '0.25rem 0.75rem', borderColor: 'var(--blue)' }}>Accept Request</button>
                      )}
                      {req.status === 'Confirmed' && (
                        <button onClick={() => handleApprove(req._id)} className="btn btn-outline text-xs text-green-500" style={{ padding: '0.25rem 0.75rem', borderColor: 'var(--green)' }}>≡ƒöÆ Confirm & Lock</button>
                      )}
                      <button onClick={() => handleReject(req._id)} className="btn btn-outline text-xs" style={{ padding: '0.25rem 0.75rem', color: 'var(--red)', borderColor: 'var(--red)' }}>Cancel</button>
                    </div>
                  )}
                  {req.status === 'PreApproved' && (
                    <div className="flex gap-2 items-center" style={{ justifyContent: 'flex-end' }}>
                      <span className="text-xs text-slate-500" style={{ marginRight: '0.5rem' }}>Waiting on Vendor...</span>
                      <button onClick={() => handleReject(req._id)} className="btn btn-outline text-xs" style={{ padding: '0.25rem 0.75rem', color: 'var(--red)', borderColor: 'var(--red)' }}>Cancel</button>
                    </div>
                  )}
                  {req.status === 'Approved' && (
                    <span className="text-sm text-green-500 font-semibold">≡ƒöÆ Locked</span>
                  )}
                  {req.status === 'Rejected' && (
                    <span className="text-sm" style={{ color: 'var(--gray-400)' }}>Cancelled</span>
                  )}
                </td>
              </tr>
            ))}
            {requests.length === 0 && (
              <tr>
                <td colSpan="5" style={{ padding: '2rem 0', textAlign: 'center', color: 'var(--gray-500)' }}>No booking requests pending.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default BookingRequests;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';

const EditStall = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    stallName: '',
    stallNumber: '',
    stallType: 'Food',
    eventName: '',
    size: 'Standard',
    locationCategory: 'Standard',
    price: '30 000',
    locationZone: 'Zone A',
    description: '',
    status: 'Available'
  });

  useEffect(() => {
    const fetchStall = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/stalls/${id}`);
        if (res.data.success) {
          setFormData(res.data.data);
        }
      } catch (err) {
        toast.error('Stall not found');
        navigate('/admin/stalls/list');
      }
    };
    fetchStall();
  }, [id]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => {
      const newData = { ...prev, [name]: value };
      if (name === 'locationCategory') {
        if (value === 'Premium') newData.price = '50 000';
        else if (value === 'Standard') newData.price = '30 000';
        else if (value === 'Basic') newData.price = '15 000';
      }
      return newData;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const submitData = {
        ...formData,
        price: Number(formData.price.toString().replace(/\s/g, ''))
      };

      const res = await axios.put(`http://localhost:5000/api/stalls/${id}`, submitData);
      if (res.data.success) {
        toast.success('Stall updated successfully!');
        navigate('/admin/stalls/list');
      }
    } catch (err) {
      toast.error('Error updating stall: ' + (err.response?.data?.message || err.message));
      console.error(err);
