            </div>
            <div className="form-group">
              <label className="form-label">Stall Number (Map ID)</label>
              <input type="text" name="stallNumber" className="form-control" required value={formData.stallNumber} onChange={handleChange} />
            </div>

            <div className="form-group">
              <label className="form-label">Stall Type</label>
              <select name="stallType" className="form-control" value={formData.stallType} onChange={handleChange}>
                <option value="Food">Food Stall</option>
                <option value="Sponsor">Sponsor Booth</option>
                <option value="Shop">Retail Shop</option>
                <option value="Game">Game Stall</option>
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Event Name</label>
