            </div>

            <div className="form-group">
              <label className="form-label">Location Category</label>
              <select name="locationCategory" className="form-control" value={formData.locationCategory || 'Standard'} onChange={handleChange}>
                <option value="Premium">Premium (Near Stage) - 50,000 LKR</option>
