import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

const StallList = () => {
  const [stalls, setStalls] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchStalls = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/stalls');
      if (res.data.success) {
        setStalls(res.data.data);
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchStalls();
  }, []);

  const formatPrice = (val) => {
    if (!val) return '0';
    return val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, " ");
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this stall? This action cannot be undone.")) return;
    try {
      await axios.delete(`http://localhost:5000/api/stalls/${id}`);
      toast.success('Stall deleted successfully!');
      fetchStalls();
    } catch (err) {
      console.error(err);
      toast.error('Error deleting stall');
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'Available': return <span className="badge badge-success">Available</span>;
      case 'Booked': return <span className="badge badge-neutral bg-gray" style={{ backgroundColor: 'var(--gray-300)' }}>Booked</span>;
      case 'Reserved': return <span className="badge badge-warning">Pending</span>;
      default: return <span className="badge badge-neutral">{status}</span>;
    }
  };

  const filteredStalls = stalls.filter(s => {
    if (!searchTerm) return true;
    const term = searchTerm.toLowerCase();
    return s.stallName.toLowerCase().startsWith(term) || 
           s.eventName.toLowerCase().startsWith(term) ||
           s.stallNumber.toLowerCase().startsWith(term);
  });

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Manage Stalls</h1>
          <p className="page-subtitle">View and edit all generated stalls</p>
        </div>
        <Link to="/admin/stalls/add" className="btn btn-primary">+ Add New Stall</Link>
      </div>

      <div className="card">
        <div className="mb-6 flex gap-4 items-center">
          <div style={{ position: 'relative', width: '100%', maxWidth: '350px' }}>
            <span style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', opacity: '0.5' }}>≡ƒöì</span>
            <input 
              type="text" 
              className="form-control" 
              placeholder="Search by stall name or starting letter..." 
              style={{ paddingLeft: '2.5rem', borderRadius: '12px' }}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
          <thead>
            <tr className="text-slate-500" style={{ borderBottom: '1px solid var(--gray-200)' }}>
              <th style={{ padding: '1rem 0' }}>Stall info</th>
              <th style={{ padding: '1rem 0' }}>Event Details</th>
              <th style={{ padding: '1rem 0' }}>Price</th>
              <th style={{ padding: '1rem 0' }}>Status</th>
              <th style={{ padding: '1rem 0', textAlign: 'right' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredStalls.map(stall => (
              <tr key={stall._id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                <td style={{ padding: '1rem 0' }}>
                  <div className="font-semibold">{stall.stallName}</div>
                  <div className="text-xs text-slate-500">ID: {stall.stallNumber} ΓÇó {stall.stallType} ΓÇó {stall.locationZone}</div>
                </td>
                <td style={{ padding: '1rem 0' }}>{stall.eventName}</td>
                <td style={{ padding: '1rem 0' }}><span className="text-slate-500 text-xs" style={{ fontWeight: 'bold' }}>LKR</span> {formatPrice(stall.price)}</td>
                <td style={{ padding: '1rem 0' }}>
                  {getStatusBadge(stall.status)}
                </td>
                <td style={{ padding: '1rem 0', textAlign: 'right' }}>
                  <Link to={`/admin/stalls/edit/${stall._id}`} className="btn btn-outline text-xs" style={{ padding: '0.25rem 0.75rem', marginRight: '0.5rem' }}>Edit</Link>
                  <button onClick={() => handleDelete(stall._id)} className="btn btn-danger text-xs" style={{ padding: '0.25rem 0.75rem' }}>Delete</button>
                </td>
              </tr>
            ))}
            {filteredStalls.length === 0 && (
              <tr>
                <td colSpan="5" style={{ padding: '2rem 0', textAlign: 'center', color: 'var(--gray-500)' }}>No stalls found.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

