import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const BookingRequestForm = () => {
  const { stallId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [stall, setStall] = useState(null);

  const [formData, setFormData] = useState({
    vendorName: user?.name || '',
    contactNumber: user?.contactNumber || '',
    businessName: user?.businessName || '',
    itemsToSell: '',
    notes: ''
  });

  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});

  useEffect(() => {
    const fetchStall = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/stalls/${stallId}`);
        if (res.data.success) {
          setStall(res.data.data);
        }
      } catch (err) {
        toast.error('Stall not found');
        navigate('/vendor/stalls');
      }
    };
    fetchStall();
  }, [stallId]);

  const validateField = (name, value) => {
    let error = null;
    const trimValue = value.trim();

    if (name === "contactNumber") {
      if (!trimValue) error = "Contact number is required.";
      else if (!/^\d{10}$/.test(trimValue)) error = "Phone number must be exactly 10 digits (e.g. 0712345678).";
    }

    if (name === "businessName") {
      if (!trimValue) error = "Business name is required.";
      else if (!/^[A-Za-z\s]+$/.test(trimValue)) error = "Business name must contain only letters and spaces.";
      else if (trimValue.length < 5 || trimValue.length > 35) error = "Business name must be between 5 and 35 characters.";
    }

    return error;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    // For contact number, prevent typing letters directly
    if (name === "contactNumber" && value && !/^\d*$/.test(value)) {
      return;
    }

    setFormData({ ...formData, [name]: value });

    if (touched[name]) {
      setErrors((prev) => ({ ...prev, [name]: validateField(name, value) }));
    }
  };

  const handleBlur = (e) => {
    const { name, value } = e.target;
    setTouched((prev) => ({ ...prev, [name]: true }));
    setErrors((prev) => ({ ...prev, [name]: validateField(name, value) }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validate all before submit
    const newErrors = {};
    Object.keys(formData).forEach(key => {
      const err = validateField(key, formData[key] || '');
      if (err) newErrors[key] = err;
      touched[key] = true;
    });
    setTouched({ ...touched });
    setErrors(newErrors);

    if (Object.values(newErrors).some(err => err !== null)) {
      return;
    }

    try {
      const payload = {
        stallId,
        ...formData
      };
      const res = await axios.post('http://localhost:5000/api/stall-bookings', payload);
      if (res.data.success) {
        toast.success('Booking request submitted successfully!');
        navigate('/vendor/my-bookings');
      }
    } catch (err) {
      toast.error(err.response?.data?.message || 'Error submitting request');
      console.error(err);
    }
  };

  if (!stall) return <div>Loading stall details...</div>;

  return (
    <>
      <style>
        {`
          .invalid-border { border-color: var(--red) !important; outline-color: var(--red); }
          .valid-border { border-color: var(--green) !important; }
          .error-text { color: var(--red); font-size: 0.75rem; margin-top: 0.25rem; font-weight: 500; display: block; }
        `}
      </style>

      <div className="page-header">
        <div>
          <h1 className="page-title">Request Stall Booking</h1>
          <p className="page-subtitle">Submit details for {stall.stallName}</p>
        </div>
      </div>

      <div className="grid gap-8" style={{ gridTemplateColumns: '1fr 300px' }}>
        <div className="card">
          <h3 style={{ marginBottom: '1.5rem' }}>Vendor Details</h3>
          <form onSubmit={handleSubmit}>
            <div className="grid grid-cols-2 gap-6">
              <div className="form-group">
                <label className="form-label">Vendor Name *</label>
                <input type="text" name="vendorName" className="form-control" value={formData.vendorName} readOnly style={{ backgroundColor: 'var(--gray-50)' }} />
              </div>
              <div className="form-group">
                <label className="form-label">Contact Number *</label>
                <input 
                  type="text" 
                  name="contactNumber" 
                  className={`form-control ${touched.contactNumber ? (errors.contactNumber ? 'invalid-border' : 'valid-border') : ''}`} 
                  required 
                  onChange={handleChange} 
                  onBlur={handleBlur}
                  value={formData.contactNumber}
                  placeholder="07X XXX XXXX" 
                  maxLength="10"
                />
                {errors.contactNumber && touched.contactNumber && <span className="error-text">{errors.contactNumber}</span>}
              </div>

              <div className="form-group col-span-full">
                <label className="form-label">Business / Brand Name *</label>
                <input 
                  type="text" 
                  name="businessName" 
                  className={`form-control ${touched.businessName ? (errors.businessName ? 'invalid-border' : 'valid-border') : ''}`} 
                  required 
                  onChange={handleChange} 
                  onBlur={handleBlur}
                  value={formData.businessName}
                  placeholder="e.g. Tasty Bites" 
                  maxLength="35"
                />
                {errors.businessName && touched.businessName && <span className="error-text">{errors.businessName}</span>}
              </div>

              <div className="form-group col-span-full">
                <label className="form-label">Items to Sell / Purpose *</label>
                <input type="text" name="itemsToSell" className="form-control" value={formData.itemsToSell} required onChange={handleChange} placeholder="e.g. Burgers, Fries, Soft Drinks" />
              </div>
            </div>

            <div className="form-group mt-4">
              <label className="form-label">Additional Notes (Optional)</label>
              <textarea name="notes" className="form-control" rows="3" onChange={handleChange} placeholder="Any specific power or space requirements?"></textarea>
            </div>

            <div className="mt-8 flex gap-4" style={{ justifyContent: 'flex-start' }}>
              <button type="submit" className="btn btn-primary">Submit Booking Request</button>
              <button type="button" className="btn btn-outline" onClick={() => navigate('/vendor/stalls')}>Cancel</button>
            </div>
          </form>
        </div>

        <div>
          <div className="card" style={{ position: 'sticky', top: '100px' }}>
            <h3 style={{ fontSize: '1rem', marginBottom: '1rem', paddingBottom: '0.5rem', borderBottom: '1px solid var(--gray-200)' }}>Selected Stall Summary</h3>

            <div className="font-bold text-2xl" style={{ color: 'var(--blue-dark)' }}>{stall.stallNumber}</div>
            <div className="font-semibold mb-2">{stall.stallName}</div>

            <div className="text-sm mb-4" style={{ color: 'var(--gray-600)' }}>
              {stall.locationZone} ΓÇó {stall.size} Size
            </div>

            <div className="p-4" style={{ backgroundColor: 'var(--gray-50)', borderRadius: 'var(--radius-md)' }}>
              <div className="flex justify-between mb-2">
                <span className="text-slate-500 text-sm">Price</span>
                <span className="font-semibold">LKR {stall.price}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-slate-500 text-sm">Event</span>
                <span className="font-semibold text-sm" style={{ textAlign: 'right', maxWidth: '120px' }}>{stall.eventName}</span>
              </div>
            </div>

            <div className="mt-4 text-xs" style={{ color: 'var(--gray-400)' }}>
              Note: Submitting this request will hold the stall locally until an admin approves it.
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

