import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const MyBookings = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [requests, setRequests] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [now, setNow] = useState(new Date().getTime());

  useEffect(() => {
    const interval = setInterval(() => {
      setNow(new Date().getTime());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const getRemainingTime = (createdAt) => {
    const expiryTimestamp = new Date(createdAt).getTime() + 15 * 60000;
    const diff = expiryTimestamp - now;
    if (diff <= 0) return null;
    const mins = Math.floor(diff / 60000);
    const secs = Math.floor((diff % 60000) / 1000);
    return `${mins}m ${secs}s`;
  };

  const fetchRequests = async () => {
    if (!user?.name) return;
    try {
      const res = await axios.get(`http://localhost:5000/api/stall-bookings/my?vendor=${user.name}`);
      if (res.data.success) {
        setRequests(res.data.data);
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, [user]);

  const handleDelete = async (id, isRecord = false) => {
    if (!window.confirm(isRecord ? "Are you sure you want to remove this record?" : "Are you sure you want to cancel this request?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/stall-bookings/${id}`);
      toast.success(isRecord ? 'Record removed successfully!' : 'Booking request cancelled successfully!');
      fetchRequests();
    } catch (err) {
      toast.error('Error removing: ' + (err.response?.data?.message || err.message));
    }
  };

  const handleUpdate = async (id) => {
    try {
      await axios.put(`http://localhost:5000/api/stall-bookings/${id}`, editForm);
      toast.success('Booking updated successfully!');
      setEditingId(null);
      fetchRequests();
    } catch (err) {
      toast.error('Error updating booking: ' + (err.response?.data?.message || err.message));
    }
  };

  const handleConfirm = (req) => {
    navigate('/vendor/booking-payment', { state: { booking: req } });
  };

  const startEdit = (req) => {
    setEditingId(req._id);
    setEditForm({
      contactNumber: req.contactNumber,
      businessName: req.businessName,
      itemsToSell: req.itemsToSell,
      notes: req.notes || ''
    });
  };

  const handleViewPass = (req) => {
    toast.success(
      `≡ƒÄƒ∩╕Å Booking Pass\nStall: ${req.stallNumber} - ${req.stallName}\nEvent: ${req.eventName}\nStatus: Approved Γ£à`,
      { duration: 5000 }
    );
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">My Requests</h1>
          <p className="page-subtitle">Track your booking status</p>
        </div>
      </div>

      <div className="card">
        <h3 style={{ marginBottom: '1.5rem', fontSize: '1.125rem' }}>Request History</h3>

        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
          <thead>
            <tr className="text-slate-500 text-sm" style={{ borderBottom: '1px solid var(--gray-200)' }}>
              <th style={{ padding: '1rem 0' }}>Event Details</th>
              <th style={{ padding: '1rem 0' }}>Stall Info</th>
              <th style={{ padding: '1rem 0' }}>Request Date</th>
              <th style={{ padding: '1rem 0' }}>Status</th>
              <th style={{ padding: '1rem 0', textAlign: 'right' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map(req => (
              <tr key={req._id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                <td style={{ padding: '1rem 0' }}>
                  <div className="font-semibold text-slate-900">{req.eventName}</div>
                  <div className="text-xs text-slate-500">Business: {req.businessName}</div>
                </td>
                <td style={{ padding: '1rem 0' }}>
                  <div style={{ fontWeight: '500' }}>Stall {req.stallNumber}</div>
                  <div className="text-xs text-slate-500">{req.stallName}</div>
                </td>
                <td className="text-sm" style={{ padding: '1rem 0' }}>
                  {new Date(req.createdAt).toLocaleDateString()}
                </td>
                <td style={{ padding: '1rem 0' }}>
                  {req.status === 'Pending' && (
                    <span className="badge badge-warning">Awaiting Admin Approval</span>
                  )}
                  {req.status === 'PreApproved' && (
                    <div className="flex flex-col" style={{ gap: '4px' }}>
                      <span className="badge badge-warning text-white" style={{ backgroundColor: 'var(--orange)' }}>Awaiting Payment</span>
                      {getRemainingTime(req.updatedAt) ? (
                        <span className="text-xs font-semibold" style={{ color: 'var(--red)' }}>
                          ΓÅ▒∩╕Å Expires in {getRemainingTime(req.updatedAt)}
                        </span>
                      ) : (
                        <span className="text-xs font-semibold" style={{ color: 'var(--red)' }}>
                          Expired
                        </span>
                      )}
                    </div>
                  )}
                  {req.status === 'Confirmed' && <span className="badge badge-success text-white" style={{ backgroundColor: 'var(--blue)' }}>Payment Pending Verification</span>}
                  {req.status === 'Approved' && <span className="badge badge-success">Locked & Approved</span>}
                  {req.status === 'Rejected' && <span className="badge badge-danger">Cancelled/Expired</span>}
                </td>
                <td style={{ padding: '1rem 0', textAlign: 'right' }}>
                  {req.status === 'Approved' ? (
                    <button onClick={() => handleViewPass(req)} className="btn btn-outline text-xs text-green-500" style={{ padding: '0.25rem 0.75rem', borderColor: 'var(--green)' }}>≡ƒÄƒ∩╕Å View Pass</button>
                  ) : req.status === 'PreApproved' ? (
                    <div className="flex gap-2 items-center" style={{ justifyContent: 'flex-end' }}>
                      {getRemainingTime(req.updatedAt) && (
                         <button onClick={() => handleConfirm(req)} className="btn btn-primary text-xs" style={{ padding: '0.25rem 0.75rem', backgroundColor: '#10b981', borderColor: '#10b981' }}>≡ƒÆ│ Pay Now</button>
                      )}
                      <button className="btn btn-outline text-xs" style={{ padding: '0.25rem 0.75rem', borderColor: '#ef4444', color: '#ef4444' }} onClick={() => handleDelete(req._id, false)}>≡ƒùæ∩╕Å Cancel</button>
                    </div>
                  ) : req.status === 'Pending' ? (
                    <button className="btn btn-outline text-xs" style={{ padding: '0.25rem 0.75rem', borderColor: '#ef4444', color: '#ef4444' }} onClick={() => handleDelete(req._id, false)}>≡ƒùæ∩╕Å Cancel Request</button>
                  ) : req.status === 'Rejected' ? (
                    <button className="btn btn-outline text-xs text-slate-500" style={{ padding: '0.25rem 0.75rem', borderColor: 'var(--gray-400)' }} onClick={() => handleDelete(req._id, true)}>≡ƒùæ∩╕Å Delete Record</button>
                  ) : (
                    <span className="text-xs" style={{ color: 'var(--gray-400)' }}>Processing...</span>
                  )}
                </td>
              </tr>
            ))}
            {editingId && (
              <tr>
                <td colSpan="5" style={{ padding: '1.5rem', backgroundColor: '#f8fafc', borderBottom: '1px solid var(--gray-200)' }}>
                  <div className="font-bold mb-4 text-sliit-navy">Γ£Å∩╕Å Editing Reference #{editingId.slice(-6)}</div>
                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                      <label className="text-[0.8rem] font-semibold">Contact Number</label>
                      <input className="form-control" value={editForm.contactNumber} onChange={e => setEditForm({...editForm, contactNumber: e.target.value})} />
                    </div>
                    <div>
                      <label className="text-[0.8rem] font-semibold">Business Name</label>
                      <input className="form-control" value={editForm.businessName} onChange={e => setEditForm({...editForm, businessName: e.target.value})} />
                    </div>
                    <div className="col-span-full">
                      <label className="text-[0.8rem] font-semibold">Items to Sell</label>
                      <input className="form-control" value={editForm.itemsToSell} onChange={e => setEditForm({...editForm, itemsToSell: e.target.value})} />
                    </div>
                  </div>
                  <div className="flex gap-2" style={{ justifyContent: 'flex-end' }}>
                    <button className="btn btn-outline" onClick={() => setEditingId(null)}>Cancel</button>
                    <button className="btn btn-primary" onClick={() => handleUpdate(editingId)}>Save Changes</button>
                  </div>
                </td>
              </tr>
            )}
            {requests.length === 0 && (
              <tr>
                <td colSpan="5" style={{ padding: '3rem 0', textAlign: 'center', color: 'var(--gray-500)' }}>You haven't made any booking requests yet.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default MyBookings;

