            <div className="flex flex-col gap-4">
              <div className="flex items-center gap-3 text-sm" style={{ color: 'var(--gray-600)' }}>
                <div className="legend-dot bg-white" style={{ borderColor: 'var(--blue)' }}></div>
                <span>Available</span>
              </div>
              <div className="flex items-center gap-3 text-sm" style={{ color: 'var(--gray-600)' }}>
                <div className="legend-dot" style={{ backgroundColor: 'var(--orange-light)', borderColor: 'var(--orange)' }}></div>
                <span>Pending</span>
              </div>
              <div className="flex items-center gap-3 text-sm" style={{ color: 'var(--gray-600)' }}>
                <div className="legend-dot" style={{ backgroundColor: 'var(--gray-200)', borderColor: 'var(--gray-400)' }}></div>
                <span>Booked</span>
              </div>
              <div className="flex items-center gap-3 text-sm text-slate-900 font-semibold mt-2">
                <div className="legend-dot" style={{ backgroundColor: 'var(--blue-dark)', borderColor: 'var(--blue-dark)' }}></div>
                <span>Selected</span>
              </div>
            </div>
          </div>

          {/* Interactive Map Area */}
          <div style={{ position: 'relative', height: '500px', backgroundColor: '#F8FAFC', overflow: 'hidden' }}>
            <svg width="100%" height="100%" viewBox="0 0 800 500" style={{ position: 'absolute', top: 0, left: 0 }}>
              {/* Map Background Shapes */}
              <rect x="150" y="50" width="500" height="150" fill="#E2E8F0" rx="16" />
              <rect x="150" y="250" width="200" height="150" fill="#E2E8F0" rx="16" />
              <rect x="450" y="250" width="200" height="150" fill="#E2E8F0" rx="16" />

              <rect x="350" y="470" width="100" height="30" fill="var(--gray-500)" rx="8" />
              <text x="400" y="490" textAnchor="middle" fill="var(--white)" fontSize="12" fontWeight="bold">ENTRANCE</text>

              {/* Dynamic Stalls */}
              {stalls.map(stall => {
                const isSelected = selectedStall?._id === stall._id;
                // For this demo, let's adjust Y coords so they fit in 500px map height
                const adjY = stall.y * 0.8; 

                return (
                  <g 
                    key={stall._id} 
                    transform={`translate(${stall.x}, ${adjY})`}
                    onClick={() => handleStallClick(stall)}
                    style={{ cursor: 'pointer', transition: 'all 0.2s' }}
                  >
                    <rect 
                      x="-25" 
                      y="-15" 
                      width="50" 
                      height="30" 
                      rx="6"
                      fill={isSelected ? 'var(--blue-dark)' : getStallColor(stall.status)}
                      stroke={isSelected ? 'var(--blue-dark)' : getBorderColor(stall.status)}
                      strokeWidth="2"
                    />
                    <text 
                      x="0" 
                      y="5" 
                      textAnchor="middle" 
                      fill={isSelected ? 'var(--white)' : getTextColor(stall.status)}
                      fontSize="12"
                      fontWeight="bold"
                    >
                      {stall.stallNumber || 'A1'}
                    </text>
                  </g>
                );
              })}
            </svg>
          </div>

          {/* Selected Stall Panel */}
          <div className="bg-white" style={{ padding: '1.5rem', borderLeft: '1px solid var(--gray-100)' }}>
            <h4 style={{ fontSize: '1rem', fontWeight: '700', color: 'var(--black)', marginBottom: '0.25rem' }}>Selected Stall</h4>
            <p className="text-sm text-slate-500 mb-8">Review details before booking.</p>

            {selectedStall ? (
              <div style={{ backgroundColor: 'var(--gray-50)', padding: '1.5rem', borderRadius: 'var(--radius-lg)', border: '1px solid var(--gray-200)' }}>
                <div className="flex justify-between items-center mb-4">
                  <div className="text-3xl font-extrabold leading-none" style={{ color: 'var(--blue-dark)' }}>{selectedStall.stallNumber}</div>
                  {selectedStall.status === 'Available' && <div className="text-xs font-bold text-green-500" style={{ padding: '0.25rem 0.5rem', backgroundColor: 'var(--green-light)', borderRadius: '4px' }}>AVAILABLE</div>}
                  {selectedStall.status === 'Reserved' && <div className="text-xs font-bold" style={{ padding: '0.25rem 0.5rem', backgroundColor: 'var(--orange-light)', color: 'var(--orange-dark)', borderRadius: '4px' }}>PENDING</div>}
                  {selectedStall.status === 'Booked' && <div className="text-xs font-bold" style={{ padding: '0.25rem 0.5rem', backgroundColor: 'var(--gray-200)', color: 'var(--gray-600)', borderRadius: '4px' }}>BOOKED</div>}
                </div>

                <div className="text-sm mb-6" style={{ color: 'var(--gray-600)' }}>{selectedStall.locationZone} - {selectedStall.stallType}</div>

                <div className="flex justify-between mb-6" style={{ paddingBottom: '1.5rem', borderBottom: '1px solid var(--gray-200)' }}>
                  <span className="text-sm text-slate-500">Price</span>
                  <span className="font-bold">LKR {formatPrice(selectedStall.price)}</span>
                </div>

                <button 
                  onClick={() => navigate(`/vendor/stalls/request/${selectedStall._id}`)} 
                  className="btn btn-primary" style={{ width: '100%', backgroundColor: selectedStall.status === 'Available' ? 'var(--blue-dark)' : 'var(--gray-400)' }}
                  disabled={selectedStall.status !== 'Available'}
                >
                  {selectedStall.status === 'Available' ? 'Book Stall' : 'Unavailable'}
                </button>
              </div>
            ) : (
              <div className="text-center" style={{ padding: '3rem 1rem', color: 'var(--gray-400)', backgroundColor: 'var(--gray-50)', borderRadius: 'var(--radius-lg)', border: '1px dashed var(--gray-200)' }}>
                <p>Click on a stall from the map to view specs.</p>
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

export default VendorDashboard;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const VendorStalls = () => {
  const [stalls, setStalls] = useState([]);
  const [filterType, setFilterType] = useState('All');

  useEffect(() => {
    const fetchStalls = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/stalls');
        if (res.data.success) {
          // Only show available stalls to vendors
          setStalls(res.data.data.filter(s => s.status === 'Available'));
        }
      } catch (err) {
        console.error(err);
      }
    };
    fetchStalls();
  }, []);

  const filteredStalls = filterType === 'All' 
    ? stalls 
    : stalls.filter(s => s.stallType === filterType);

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Events Gallery</h1>
          <p className="page-subtitle">Browse and book available stalls</p>
        </div>
      </div>

      <div className="mb-8 flex gap-4">
        <button onClick={() => setFilterType('All')} className={`btn ${filterType === 'All' ? 'btn-primary' : 'btn-outline'}`}>All Stalls</button>
        <button onClick={() => setFilterType('Food')} className={`btn ${filterType === 'Food' ? 'btn-primary' : 'btn-outline'}`}>Food</button>
        <button onClick={() => setFilterType('Sponsor')} className={`btn ${filterType === 'Sponsor' ? 'btn-primary' : 'btn-outline'}`}>Sponsor</button>
        <button onClick={() => setFilterType('Game')} className={`btn ${filterType === 'Game' ? 'btn-primary' : 'btn-outline'}`}>Game</button>
        <button onClick={() => setFilterType('Shop')} className={`btn ${filterType === 'Shop' ? 'btn-primary' : 'btn-outline'}`}>Retail</button>
      </div>

      <div className="grid gap-6" style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))' }}>
        {filteredStalls.map(stall => (
          <div key={stall._id} className="card flex flex-col">
            <div className="mb-4" style={{ padding: '0 0 1rem 0', borderBottom: '1px solid var(--gray-100)' }}>
              <div className="flex justify-between items-start">
                <div>
                  <div className="font-bold text-lg text-slate-900">{stall.stallName}</div>
                  <div className="text-sm text-slate-500">{stall.eventName}</div>
                </div>
                <span className="badge badge-success">Available</span>
              </div>
            </div>

            <div className="flex-1">
              <div className="grid grid-cols-2 gap-2 text-sm mb-4">
                <div><span className="text-slate-500">Type:</span> {stall.stallType}</div>
                <div><span className="text-slate-500">Zone:</span> {stall.locationZone}</div>
                <div><span className="text-slate-500">Size:</span> {stall.size}</div>
                <div><span className="text-slate-500">Price:</span> LKR {stall.price}</div>
              </div>
            </div>

            <div className="flex gap-2 mt-4">
              <Link to={`/stalls/${stall._id}`} className="btn btn-outline flex-1">View Details</Link>
              <Link to={`/vendor/stalls/request/${stall._id}`} className="btn btn-primary flex-1">Request Stall</Link>
            </div>
          </div>
        ))}

        {filteredStalls.length === 0 && (
          <div className="col-span-full text-center p-12 text-slate-500 bg-white" style={{ borderRadius: 'var(--radius-lg)' }}>
            No stalls available for this category right now.
          </div>
        )}
      </div>
    </div>
  );
};

export default VendorStalls;
